import 'package:dio/dio.dart';import 'package:flutter_test/flutter_test.dart';import 'package:meme_arena/core/config/api_config.dart';import 'package:meme_arena/core/config/content_url_resolver.dart';import 'package:meme_arena/core/errors/app_error.dart';import 'package:meme_arena/features/models.dart';
void main(){test('base URL config',(){expect(ApiConfig().baseUrl,'http://10.0.2.2:8080');expect(ApiConfig(baseUrl:'http://x/').baseUrl,'http://x');});test('content URL resolver',(){final r=ContentUrlResolver(ApiConfig(baseUrl:'http://api'));expect(r.resolve('/api/v1/media/1/content'),'http://api/api/v1/media/1/content');expect(r.resolve('https://cdn/x'),'https://cdn/x');});test('error response parsing',(){final e=AppError.fromDio(DioException(requestOptions:RequestOptions(),response:Response(requestOptions:RequestOptions(),statusCode:400,data:{'code':'BAD','message':'Ошибка','fieldErrors':{'title':'required'}})));expect(e.message,'Ошибка');expect(e.fieldErrors['title'],'required');});test('nickname validation',(){expect(validateNickname('ab'),isNotNull);expect(validateNickname('valid_ник'),isNull);});test('leaderboard period mapping',(){expect(periodCode(2),'ALL_TIME');});test('rank mapping',(){expect(rankTitle('OBSERVER'),'Наблюдатель');expect(rankTitle('SCOUT'),'Мемный скаут');expect(rankTitle('TREND_HUNTER'),'Охотник за трендами');expect(rankTitle('MEME_ORACLE'),'Мемный оракул');});test('parsing profile scout stats and achievements',(){final p=UserProfile.fromJson({'id':'u1','nickname':'nick','votesCount':15,'submittedMemesCount':2,'scoutPoints':120,'rank':'SCOUT','predictionsCount':3,'successfulPredictions':2,'failedPredictions':1,'expiredPredictions':4,'accuracy':0.66,'currentSuccessStreak':2,'bestSuccessStreak':5,'achievements':[{'code':'FIRST_HIT','title':'Первое попадание','description':'ok'}]});expect(p.scoutPoints,120);expect(p.rank,'SCOUT');expect(p.accuracy,0.66);expect(p.achievements.single.code,'FIRST_HIT');});test('parsing vote prediction',(){final v=VoteResult.fromJson({'prediction':{'created':true,'predictionId':'p1','message':'Прогноз сохранён'}});expect(v.prediction.created,isTrue);expect(v.prediction.message,'Прогноз сохранён');});test('prediction status mapping',(){final p=PredictionItem.fromJson({'id':'p','status':'EXPIRED','meme':{'title':'m'},'pointsAwarded':0});expect(p.statusTitle,'Истёкший');});test('scout leaderboard parsing',(){final x=ScoutLeaderboardItem.fromJson({'position':1,'nickname':'n','rank':'SCOUT','scoutPoints':100,'accuracy':0.5});expect(x.position,1);expect(rankTitle(x.rank),'Мемный скаут');});}
